local TeamConstants = {}

TeamConstants.TeamSizeTarget = 3

TeamConstants.Ids = {
	Sun = "sun",
	Moon = "moon",
	Spectator = "spectator",
}

TeamConstants.Teams = {
	sun = {
		id = "sun",
		displayName = "Team Sun",
		shortName = "Sun",
		color = Color3.fromRGB(255, 188, 82),
	},
	moon = {
		id = "moon",
		displayName = "Team Moon",
		shortName = "Moon",
		color = Color3.fromRGB(122, 160, 255),
	},
	spectator = {
		id = "spectator",
		displayName = "Spectator",
		shortName = "Spec",
		color = Color3.fromRGB(180, 188, 205),
	},
}

TeamConstants.CombatTeams = {
	sun = true,
	moon = true,
}

function TeamConstants.get(teamId)
	return TeamConstants.Teams[teamId]
end

function TeamConstants.isValid(teamId)
	return TeamConstants.Teams[teamId] ~= nil
end

function TeamConstants.isCombatTeam(teamId)
	return TeamConstants.CombatTeams[teamId] == true
end

function TeamConstants.listCombatTeams()
	return {
		TeamConstants.Teams.sun,
		TeamConstants.Teams.moon,
	}
end

return TeamConstants

local Signal = {}
Signal.__index = Signal

function Signal.new()
	return setmetatable({
		_bindable = Instance.new("BindableEvent"),
	}, Signal)
end

function Signal:Connect(callback)
	return self._bindable.Event:Connect(callback)
end

function Signal:Fire(...)
	self._bindable:Fire(...)
end

function Signal:Destroy()
	self._bindable:Destroy()
	self._bindable = nil
end

return Signal

local MathUtil = {}

function MathUtil.clamp01(value)
	return math.clamp(value or 0, 0, 1)
end

function MathUtil.flatUnit(vector, fallback)
	local flat = Vector3.new(vector.X, 0, vector.Z)
	if flat.Magnitude < 0.001 then
		return fallback or Vector3.new(0, 0, -1)
	end
	return flat.Unit
end

function MathUtil.clampMagnitude(vector, maxMagnitude)
	local magnitude = vector.Magnitude
	if magnitude <= maxMagnitude then
		return vector
	end
	return vector.Unit * maxMagnitude
end

function MathUtil.ratio(value, maxValue)
	if not maxValue or maxValue <= 0 then
		return 0
	end
	return MathUtil.clamp01((value or 0) / maxValue)
end

return MathUtil

